// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
// See the License for the specific language governing permissions and
// limitations under the License.
//

#include "asm.h"
#include "libc.h"
#include "registers.h"
#include "thread.h"
#include "trap.h"
#include "vm_address_space.h"

struct interrupt_frame
{
    unsigned int gpr[32];
    unsigned int pc;
    unsigned int flags;
    unsigned int subcycle;
};

void dump_interrupt_frame(int trap_cause, unsigned int trap_address,
    const struct interrupt_frame*);
extern int handle_syscall(int index, int arg0, int arg1, int arg2, int arg3, int arg4,
                          int arg5);

static const char *TRAP_NAMES[] =
{
    "reset",
    "Illegal Instruction",
    "Privileged Op",
    "Interrupt",
    "Syscall",
    "Unaligned Access",
    "Page Fault",
    "TLB Miss",
    "Illegal Store",
    "Illegal Supervisor Page Access",
    "Page Non Executable"
};

static interrupt_handler_t handlers[NUM_INTERRUPTS];
static unsigned int enabled_interrupts[MAX_HW_THREADS];

// These are set by the user_copy routine.
unsigned int fault_handler[MAX_HW_THREADS];

void unmask_interrupt(int interrupt)
{
    int hwthid = current_hw_thread();
    enabled_interrupts[hwthid] |= 1 << interrupt;
    __builtin_nyuzi_write_control_reg(CR_INTERRUPT_ENABLE, enabled_interrupts[hwthid]);
}

void register_interrupt_handler(int interrupt, interrupt_handler_t handler)
{
    // XXX lock
    handlers[interrupt] = handler;
    unmask_interrupt(interrupt);
}

static void handle_interrupt()
{
    unsigned int interrupt_bitmap = __builtin_nyuzi_read_control_reg(CR_INTERRUPT_PENDING);

    while (interrupt_bitmap)
    {
        int next_int = __builtin_ctz(interrupt_bitmap);
        interrupt_bitmap &= ~(1 << next_int);
        if (handlers[next_int] == 0)
        {
            kprintf("No handler for interrupt %d", next_int);
            panic("STOPPING");
        }

        (*handlers[next_int])();
    }
}

void ack_interrupt(int interrupt)
{
    __builtin_nyuzi_write_control_reg(CR_INTERRUPT_ACK, 1 << interrupt);
}

static void __attribute__((noreturn)) bad_fault(int trap_cause, unsigned int trap_address,
    struct interrupt_frame *frame)
{
    if (frame->flags & FLAG_SUPERVISOR_EN)
    {
        kprintf("Invalid kernel page fault thread %d\n", current_thread()->id);
        dump_interrupt_frame(trap_cause, trap_address, frame);
        panic("stopping");
    }
    else
    {
        // User space crash. Kill thread. Should kill entire process,
        // but need signals/APCs to do that.
        kprintf("user space thread %d crashed\n", current_thread()->id);
        dump_interrupt_frame(trap_cause, trap_address, frame);
        thread_exit(1);
    }
}

void handle_trap(struct interrupt_frame *frame)
{
    unsigned int address;
    int syscall_index;
    int trap_cause = __builtin_nyuzi_read_control_reg(CR_TRAP_CAUSE);

    switch (trap_cause & 0xf)
    {
        case TT_PAGE_FAULT:
        case TT_ILLEGAL_STORE:
            address = __builtin_nyuzi_read_control_reg(CR_TRAP_ADDR);
            enable_interrupts();
            if (!handle_page_fault(address, (trap_cause & 0x10) != 0))
            {
                // Jump to user_copy fault handler if set
                if (fault_handler[current_hw_thread()] != 0)
                    frame->pc = fault_handler[current_hw_thread()];
                else
                    bad_fault(trap_cause, address, frame);
            }

            disable_interrupts();
            break;

        case TT_SYSCALL:
            // Enable interrupts
            syscall_index = __builtin_nyuzi_read_control_reg(CR_SYSCALL_INDEX);
            enable_interrupts();
            frame->gpr[0] = handle_syscall(syscall_index, frame->gpr[0],
                                           frame->gpr[1], frame->gpr[2],
                                           frame->gpr[3], frame->gpr[4],
                                           frame->gpr[5]);

            frame->pc += 4;    // Next instruction
            disable_interrupts();
            break;

        case TT_INTERRUPT:
            handle_interrupt();
            break;

        default:
            bad_fault(trap_cause, 0, frame);
    }
}

void dump_interrupt_frame(int trap_cause, unsigned int trap_address,
    const struct interrupt_frame *frame)
{
    int reg;
    int trap_type = trap_cause & 0xf;

    if (trap_type <= TT_NOT_EXECUTABLE)
    {
        kprintf("%s ", TRAP_NAMES[trap_type]);
        if (trap_type == TT_UNALIGNED_ACCESS || trap_type == TT_PAGE_FAULT
                || trap_type == TT_TLB_MISS || trap_type == TT_ILLEGAL_STORE
                || trap_type == TT_SUPERVISOR_ACCESS)
        {
            kprintf("@%08x %s %s\n", trap_address,
                (trap_cause & 0x20) ? "dcache" : "icache",
                (trap_cause & 0x10) ? "store" : "load");
        }
    }
    else
        kprintf("Unknown trap cause %02x\n", trap_cause);

    kprintf("REGISTERS\n");
    for (reg = 0; reg < 32; reg++)
    {
        if (reg < 10)
            kprintf(" "); // Align single digit numbers

        kprintf("s%d %08x ", reg, frame->gpr[reg]);
        if (reg % 8 == 7)
            kprintf("\n");
    }

    kprintf("pc %08x ", frame->pc);
    kprintf("Flags: ");
    if (frame->flags & 1)
        kprintf("I");

    if (frame->flags & 2)
        kprintf("M");

    if (frame->flags & 4)
        kprintf("S");

    kprintf(" (%02x)\n\n", frame->flags);
}

//
// Copyright 2015-2016 Jeff Bush
//
// Licensed under the Apache License, Version 2.0 (the "License");
// you may not use this file except in compliance with the License.
// You may obtain a copy of the License at
//
//     http://www.apache.org/licenses/LICENSE-2.0
//
// Unless required by applicable law or agreed to in writing, software
// distributed under the License is distributed on an "AS IS" BASIS,
// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
// See the License for the specific language governing permissions and
// limitations under the License.
//

#include "asm.h"

#define TRAP_FRAME_SP_OFFSET 120
#define TRAP_FRAME_PC_OFFSET 128

//
// General trap handler. This saves all scalar registers, but does not save
// vector registers. This means the kernel cannot use vector registers and
// must save them on context switch.
//

                        .globl trap_entry
                        .type trap_entry, @function
trap_entry:             setcr s0, CR_SCRATCHPAD0        // Save s0 in scratchpad
                        setcr s1, CR_SCRATCHPAD1        // Save s1 in scratchpad

                        getcr s0, CR_SAVED_FLAGS        // Get old flags
                        and s0, s0, FLAG_SUPERVISOR_EN  // Was in supervisor mode?
                        bnz s0, is_supervisor

                        // Fault occured while thread was in user mode. Need
                        // to switch to kernel stack. First, find the current
                        // OS thread that is running.
                        getcr s0, CR_CURRENT_HW_THREAD  // Current hardware thread
                        shl s0, s0, 2                   // Multiply by 4 (bytes/entry)
                        lea s1, trap_kernel_stack_addr
                        load_32 s1, (s1)                // Get base of array
                        add_i s1, s1, s0                // Find element ptr
                        load_32 s1, (s1)                // Get kernel_stack pointer
                        store_32 sp, TRAP_FRAME_SP_OFFSET - TRAP_FRAME_SIZE(s1) // Save user stack
                        move sp, s1                     // switch stacks
                        b save_frame

                        // Already in kernel mode. Do not need to switch stacks, just
                        // decrement stack pointer to make room for trap frame.
is_supervisor:          store_32 sp, TRAP_FRAME_SP_OFFSET - TRAP_FRAME_SIZE(sp)   // save old stack

                        // Save remaining registers
save_frame:             getcr s0, CR_SCRATCHPAD0        // restore s0
                        getcr s1, CR_SCRATCHPAD1        // restore s1
                        sub_i sp, sp, TRAP_FRAME_SIZE   // Reserve space for trap frame

                        store_32 s0, 0(sp)
                        store_32 s1, 4(sp)
                        store_32 s2, 8(sp)
                        store_32 s3, 12(sp)
                        store_32 s4, 16(sp)
                        store_32 s5, 20(sp)
                        store_32 s6, 24(sp)
                        store_32 s7, 28(sp)
                        store_32 s8, 32(sp)
                        store_32 s9, 36(sp)
                        store_32 s10, 40(sp)
                        store_32 s11, 44(sp)
                        store_32 s12, 48(sp)
                        store_32 s13, 52(sp)
                        store_32 s14, 56(sp)
                        store_32 s15, 60(sp)
                        store_32 s16, 64(sp)
                        store_32 s17, 68(sp)
                        store_32 s18, 72(sp)
                        store_32 s19, 76(sp)
                        store_32 s20, 80(sp)
                        store_32 s21, 84(sp)
                        store_32 s22, 88(sp)
                        store_32 s23, 92(sp)
                        store_32 s24, 96(sp)
                        store_32 s25, 100(sp)
                        store_32 s26, 104(sp)
                        store_32 s27, 108(sp)
                        store_32 gp, 112(sp)
                        // sp was already saved at 114 on entry
                        store_32 fp, 116(sp)
                        store_32 ra, 124(sp)

                        getcr s0, CR_TRAP_PC
                        store_32 s0, TRAP_FRAME_PC_OFFSET(sp)
                        getcr s0, CR_SAVED_FLAGS
                        store_32 s0, 132(sp)
                        getcr s0, CR_SAVED_SUBCYCLE
                        store_32 s0, 136(sp)

                        move s0, sp  // pass pointer to trap frame to handle_trap

                        // Load global pointer
                        movehi gp, hi(_GLOBAL_OFFSET_TABLE_)
                        or gp, gp, lo(_GLOBAL_OFFSET_TABLE_)

                        call handle_trap

                        load_32 s1, 4(sp)
                        load_32 s2, 8(sp)
                        load_32 s3, 12(sp)
                        load_32 s4, 16(sp)
                        load_32 s5, 20(sp)
                        load_32 s6, 24(sp)
                        load_32 s7, 28(sp)
                        load_32 s8, 32(sp)
                        load_32 s9, 36(sp)
                        load_32 s10, 40(sp)
                        load_32 s11, 44(sp)
                        load_32 s12, 48(sp)
                        load_32 s13, 52(sp)
                        load_32 s14, 56(sp)
                        load_32 s15, 60(sp)
                        load_32 s16, 64(sp)
                        load_32 s17, 68(sp)
                        load_32 s18, 72(sp)
                        load_32 s19, 76(sp)
                        load_32 s20, 80(sp)
                        load_32 s21, 84(sp)
                        load_32 s22, 88(sp)
                        load_32 s23, 92(sp)
                        load_32 s24, 96(sp)
                        load_32 s25, 100(sp)
                        load_32 s26, 104(sp)
                        load_32 s27, 108(sp)
                        load_32 gp, 112(sp)
                        load_32 fp, 116(sp)
                        load_32 ra, 124(sp)

                        load_32 s0, TRAP_FRAME_PC_OFFSET(sp)
                        setcr s0, CR_TRAP_PC    // eret will jump to here
                        load_32 s0, 132(sp)     // get save flags from trap frame
                        setcr s0, CR_SAVED_FLAGS
                        load_32 s0, 136(sp)     // get subcycle from trap frame
                        setcr s0, CR_SAVED_SUBCYCLE
                        load_32 s0, 0(sp)    // Restore s0
                        load_32 sp, TRAP_FRAME_SP_OFFSET(sp) // Restore old stack pointer
                        eret

// This stores an array of addresses of kernel stacks, one for each hardware
// thread.
trap_kernel_stack_addr: .long trap_kernel_stack


//
// Jump to a user mode task.
// This is used to initially jump to user code when spawning a new thread.
//
//  void jump_to_user_mode(int argc, void *argv, unsigned int inital_pc,
//      unsigned int user_stack_ptr);
//
// Use eret to simultaneously jump to PC and switch modes.
//

                        .globl jump_to_user_mode
jump_to_user_mode:      setcr s2, CR_TRAP_PC        // Address to jump to.
                        move s10, FLAG_MMU_EN | FLAG_INTERRUPT_EN
                        setcr s10, CR_SAVED_FLAGS
                        move sp, s3
                        eret

//
// TLB miss handler.
// This is called when either an instruction or data TLB miss occurs.
// It is responsible for populating the corresponding TLB entry.
// This is invoked with the MMU disabled.
//
// Virtual address format:
// +--------------------+--------------------+------------------------+
// |  pgdir index (10)  |  pgtbl index (10)  |    page offset (12)    |
// +--------------------+--------------------+------------------------+
//
// Page directory entry:
// +----------------------------------------+-----------------------+-+
// |         page table address (20)        |       unused (9)      |P|
// +----------------------------------------+-----------------------+-+
//
// Page table entry:
// +----------------------------------------+---------------+---------+
// |            page address (20)           |   unused (5)  |G S X W P|
// +----------------------------------------+---------------+---------+
//  G - Global
//  S - Supervisor
//  X - Executable
//  W - Writable
//  P - Present
//

                    .globl tlb_miss_handler
tlb_miss_handler:   setcr s0, CR_SCRATCHPAD0    // Save s0 in scratchpad
                    setcr s1, CR_SCRATCHPAD1    // Same for s1

                    getcr s1, CR_PAGE_DIR_BASE  // Read page dir phys addr

                    // Read page directory
                    getcr s0, CR_TRAP_ADDR      // Get fault virtual address
                    shr s0, s0, 22              // Convert to page directory index
                    shl s0, s0, 2               // Multiply offset by 4 (bytes/entry)
                    add_i s0, s0, s1            // Pointer to page directory entry
                    load_32 s0, (s0)            // Read page directory entry
                    and s1, s0, 1               // Is present bit set?
                    bz s1, pte_not_present      // No page table
                    shr s0, s0, 12              // Mask off all low bits to get rounded PTE base
                    shl s0, s0, 12

                    // Read page table
                    getcr s1, CR_TRAP_ADDR      // Get fault virtual address
                    shr s1, s1, 12              // Convert to page table index
                    and s1, s1, 1023            // Mask off page directory index
                    shl s1, s1, 2               // Multiply by 4 (bytes/entry)
                    add_i s1, s1, s0            // Pointer to page table entry
                    load_32 s0, (s1)            // Read page table entry value

                    // Update TLB
update_tlb:         getcr s1, CR_TRAP_CAUSE     // Get fault reason
                    and s1, s1, 0x20            // Is DTLB miss?
                    bz s1, fill_itlb            // If no, branch to update ITLB

fill_dltb:          getcr s1, CR_TRAP_ADDR      // Get fault virtual address
                    dtlbinsert s1, s0           // Set virtual address for DTLB
                    b done

fill_itlb:          getcr s1, CR_TRAP_ADDR      // Get fault virtual address
                    itlbinsert s1, s0           // Set virtual address for ITLB

done:               getcr s0, CR_SCRATCHPAD0    // Get saved s0 from scratchpad
                    getcr s1, CR_SCRATCHPAD1    // Get saved s1
                    eret

pte_not_present:    move s0, 0                  // Null entry (present bit not set)
                    b update_tlb                // Insert this into TLB


                    .globl disable_interrupts
disable_interrupts: getcr s0, CR_FLAGS
                    and s1, s0, FLAG_MMU_EN | FLAG_SUPERVISOR_EN
                    setcr s1, CR_FLAGS
                    ret

                    .globl enable_interrupts
enable_interrupts:  getcr s0, CR_FLAGS
                    or s1, s0, FLAG_INTERRUPT_EN
                    setcr s1, CR_FLAGS
                    ret

                    .globl restore_interrupts
restore_interrupts: setcr s0, CR_FLAGS
                    ret

