int putchar(int ch)
{
    fputc(ch, stdout);
    return 1;
}

int puts(const char *s)
{
    const char *c;
    for (c = s; *c; c++)
        putchar(*c);

    putchar('\n');
    return c - s + 1;
}

int fputc(int ch, FILE *file)
{
    if (file == stdout)
    {
        char _ch = ch;
        write_console(&_ch, 1);
    }
    else if (file->write_buf)
    {
        if (file->write_offset < file->write_buf_len)
            file->write_buf[file->write_offset++] = ch;
    }
    else
        write(file->fd, &ch, 1);

    return 1;
}

